import pytest

def title_case(s: str) -> str:
    return ' '.join(word.capitalize() for word in s.split())


# Happy path tests
def test_title_case_basic():
    assert title_case("hello world") == "Hello World"


def test_title_case_multiple_words():
    assert title_case("python programming is fun") == "Python Programming Is Fun"


def test_title_case_mixed_case():
    assert title_case("hElLo WoRlD") == "Hello World"


def test_title_case_all_uppercase():
    assert title_case("HELLO WORLD") == "Hello World"


def test_title_case_with_punctuation():
    assert title_case("hello, world!") == "Hello, World!"


# Edge cases
def test_title_case_empty_string():
    assert title_case("") == ""


def test_title_case_single_word():
    assert title_case("hello") == "Hello"


def test_title_case_single_word_with_spaces():
    assert title_case("  hello  ") == "Hello"


def test_title_case_multiple_spaces_between_words():
    assert title_case("hello   world") == "Hello World"


def test_title_case_leading_trailing_spaces():
    assert title_case("  hello world  ") == "Hello World"


# Error cases
def test_title_case_non_string_input_int():
    with pytest.raises(AttributeError, match="'int' object has no attribute 'split'"):
        title_case(123)


def test_title_case_non_string_input_none():
    with pytest.raises(AttributeError, match="'NoneType' object has no attribute 'split'"):
        title_case(None)


def test_title_case_non_string_input_list():
    with pytest.raises(AttributeError, match="'list' object has no attribute 'split'"):
        title_case([1, 2, 3])
